static std::optional<APInt>
foldBinaryIntOp(unsigned Opcode, const APInt &L, const APInt &R) {
  unsigned BitWidth = L.getBitWidth();
  switch (Opcode) {
  case Instruction::Add:
    return L + R;
  case Instruction::Sub:
    return L - R;
  case Instruction::Mul:
    return L * R;
  case Instruction::SDiv:
    if (R.isZero())
      return std::nullopt;
