  case Instruction::UDiv:
    if (R.isZero())
      return std::nullopt;
    return L.udiv(R);
  case Instruction::And:
    return L & R;
  case Instruction::Or:
    return L | R;
  case Instruction::Xor:
    return L ^ R;
  case Instruction::Shl:
    if (R.uge(BitWidth))
