        if (!LC || !RC)
          continue;
        std::optional<APInt> Res =
            foldBinaryIntOp(BO->getOpcode(), LC->getValue(), RC->getValue());
        if (!Res)
          continue;
        Constant *C = ConstantInt::get(BO->getType(), *Res);
        I.replaceAllUsesWith(C);
        I.eraseFromParent();
        LocalChanged = true;
        Changed = true;
      }
    }
  }

  return Changed;
}
